import { MakeLogicType, actions, afterMount, connect, isBreakpoint, kea, listeners, path } from 'kea'
import { loaders } from 'kea-loaders'

import { metricCount } from 'lib/operationalMetrics'
import { teamLogic } from 'scenes/teamLogic'

import { visionScannersList } from '../generated/api'
import type { ReplayScannerApi } from '../generated/api.schemas'

const PAGE_LIMIT = 100

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface visionScannersListLogicValues {
    scanners: ReplayScannerApi[]
    scannersLoading: boolean
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface visionScannersListLogicActions {
    loadCurrentTeamSuccess: (
        currentTeam: null | import('~/types').TeamPublicType,
        payload?: any
    ) => {
        currentTeam: null | import('~/types').TeamPublicType
        payload?: any
    } // teamLogic
    loadScanners: () => {
        value: true
    }
    loadScannersFailure: (
        error: string,
        errorObject?: any
    ) => {
        error: string
        errorObject?: any
    }
    loadScannersSuccess: (
        scanners: ReplayScannerApi[],
        payload?: {
            value: true
        }
    ) => {
        scanners: ReplayScannerApi[]
        payload?: {
            value: true
        }
    }
}

export type visionScannersListLogicType = MakeLogicType<visionScannersListLogicValues, visionScannersListLogicActions>

/** The team's full scanner list for pickers — shared and propless so each surface doesn't refetch its own copy. */
export const visionScannersListLogic = kea<visionScannersListLogicType>([
    path(['products', 'replay_vision', 'frontend', 'logics', 'visionScannersListLogic']),

    connect(() => ({
        actions: [teamLogic, ['loadCurrentTeamSuccess']],
    })),

    actions({
        // Declared here so the action stays zero-arg despite the loader's `breakpoint` parameter.
        loadScanners: true,
    }),

    loaders(({ values }) => ({
        scanners: [
            [] as ReplayScannerApi[],
            {
                loadScanners: async (_, breakpoint) => {
                    const teamId = teamLogic.values.currentTeamId
                    if (!teamId) {
                        return []
                    }
                    try {
                        // Follow pagination so pickers never silently truncate past the server page size.
                        const all: ReplayScannerApi[] = []
                        let offset = 0
                        for (;;) {
                            const response = await visionScannersList(String(teamId), {
                                limit: PAGE_LIMIT,
                                offset,
                            })
                            // Cancel superseded loops (e.g. team switch) so a stale multi-page fetch can't win.
                            breakpoint()
                            const results = response.results ?? []
                            all.push(...results)
                            if (!response.next || results.length === 0) {
                                return all
                            }
                            offset += results.length
                        }
                    } catch (error) {
                        if (error instanceof Error && isBreakpoint(error)) {
                            throw error
                        }
                        // Degrades silently to the stale list, so count it or it is invisible.
                        metricCount('replay_vision_frontend_scanners_load_failures')
                        return values.scanners
                    }
                },
            },
        ],
    })),

    listeners(({ actions }) => ({
        // Propless/global — reload on team switch so a stale list can't offer another team's scanner ids.
        loadCurrentTeamSuccess: () => actions.loadScanners(),
    })),

    afterMount(({ actions }) => {
        actions.loadScanners()
    }),
])
